-- 1. FIX: Enable RLS on sensitive 'system_settings' table
-- Risk: Without RLS, this table might be publicly readable.
CREATE TABLE IF NOT EXISTS system_settings (
    key TEXT PRIMARY KEY,
    value JSONB NOT NULL,
    description TEXT,
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

ALTER TABLE IF EXISTS system_settings ENABLE ROW LEVEL SECURITY;

-- Policy: Only Service Role (Backend) can modify settings
DROP POLICY IF EXISTS "Service Role Full Access" ON system_settings;
CREATE POLICY "Service Role Full Access"
ON system_settings
FOR ALL
TO service_role
USING (true)
WITH CHECK (true);

-- Policy: Admins can view (assuming you verify admin via Middleware/Edge Function before querying)
-- Ideally, keep this table private to Service Role only.
-- If frontend needs to read it, create a secure RPC function.

-- 2. FIX: Add index to Foreign Keys to prevent CPU DoS
-- Risk: Large table joins without index cause 100% CPU usage.

-- Ensure 'withdrawals' table exists
CREATE TABLE IF NOT EXISTS withdrawals (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    user_id UUID REFERENCES auth.users(id),
    admin_id UUID REFERENCES admin_users(id),
    amount DECIMAL(20, 8) NOT NULL,
    currency TEXT DEFAULT 'USDT' NOT NULL,
    destination_address TEXT NOT NULL,
    status TEXT DEFAULT 'PENDING',
    tx_hash TEXT,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- Ensure 'orders' table exists
CREATE TABLE IF NOT EXISTS orders (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    user_id UUID REFERENCES auth.users(id) NOT NULL,
    symbol VARCHAR(20) NOT NULL,
    side VARCHAR(10) NOT NULL,
    type VARCHAR(20) NOT NULL,
    quantity NUMERIC NOT NULL,
    price NUMERIC,
    status VARCHAR(20) DEFAULT 'pending',
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_withdrawals_user_id ON withdrawals(user_id);
CREATE INDEX IF NOT EXISTS idx_orders_user_id ON orders(user_id);

-- Safe index creation for transactions (might be missing)
DO $$
BEGIN
    IF EXISTS (SELECT FROM pg_tables WHERE schemaname = 'public' AND tablename = 'transactions') THEN
        CREATE INDEX IF NOT EXISTS idx_transactions_user_id ON transactions(user_id);
    END IF;
END $$;

