-- 3. FIX: Data Validation Constraint for Discount Codes
-- Risk: Negative prices or >100% discount.

-- Ensure 'discount_codes' table exists
CREATE TABLE IF NOT EXISTS discount_codes (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  code TEXT UNIQUE NOT NULL,
  discount_type TEXT NOT NULL CHECK (discount_type IN ('percentage', 'fixed')),
  discount_value NUMERIC NOT NULL,
  valid_from TIMESTAMPTZ DEFAULT NOW(),
  valid_until TIMESTAMPTZ,
  max_uses INTEGER,
  current_uses INTEGER DEFAULT 0,
  applicable_tiers TEXT[],
  minimum_purchase NUMERIC,
  created_by UUID REFERENCES auth.users(id),
  notes TEXT,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

ALTER TABLE IF EXISTS discount_codes
DROP CONSTRAINT IF EXISTS check_discount_value_valid;

ALTER TABLE IF EXISTS discount_codes
ADD CONSTRAINT check_discount_value_valid
CHECK (
    (discount_type = 'percentage' AND discount_value > 0 AND discount_value <= 100) OR
    (discount_type = 'fixed' AND discount_value > 0)
);

-- 4. FIX: Cleanup Policy (Optional but recommended)
-- Ensure 'api_keys' table RLS is strict

-- Ensure 'api_keys' table exists
CREATE TABLE IF NOT EXISTS api_keys (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    user_id UUID REFERENCES auth.users(id) NOT NULL,
    label VARCHAR(50),
    access_key VARCHAR(64) NOT NULL UNIQUE,
    secret_key VARCHAR(255) NOT NULL,
    permissions JSONB DEFAULT '["read", "trade"]',
    last_used_at TIMESTAMPTZ,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    is_active BOOLEAN DEFAULT true
);

ALTER TABLE IF EXISTS api_keys ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Users can view own api keys" ON api_keys;
CREATE POLICY "Users can view own api keys"
ON api_keys
FOR SELECT
TO authenticated
USING (auth.uid() = user_id);

DROP POLICY IF EXISTS "Users can create own api keys" ON api_keys;
CREATE POLICY "Users can create own api keys"
ON api_keys
FOR INSERT
TO authenticated
WITH CHECK (auth.uid() = user_id);

DROP POLICY IF EXISTS "Users can delete own api keys" ON api_keys;
CREATE POLICY "Users can delete own api keys"
ON api_keys
FOR DELETE
TO authenticated
USING (auth.uid() = user_id);

